section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/a11y-audit-per-screen-checklist.json",
  "title": "A11y Audit per-Screen Checklist",
  "type": "object",
  "required": [
    "artefact_id",
    "screen_id",
    "checks",
    "screen_url_or_story",
    "tooling_used",
    "owner",
    "last_touched",
    "template_version",
    "status"
  ],
  "properties": {
    "artefact_id": {
      "type": "string",
      "description": "slug + ISO date or UUID",
      "minLength": 1
    },
    "owner": {
      "type": "string",
      "description": "single named owner; generic group terms forbidden",
      "minLength": 1
    },
    "last_touched": {
      "type": "string",
      "description": "ISO-8601 timestamp",
      "format": "date-time"
    },
    "template_version": {
      "type": "string",
      "description": "semver matching methodology frontmatter at write time"
    },
    "status": {
      "type": "string",
      "description": "draft|ready_for_review|approved|archived",
      "minLength": 1
    },
    "screen_id": {
      "type": "string",
      "minLength": 1
    },
    "checks": {
      "type": "array",
      "minItems": 9,
      "description": "9-row array each {check_id, pass, finding?, fix?}"
    },
    "screen_url_or_story": {
      "type": "string",
      "minLength": 1
    },
    "tooling_used": {
      "type": "array",
      "minItems": 1,
      "description": "axe | lighthouse | manual screen-reader | ..."
    }
  },
  "additionalProperties": false
}
